export const generateListingText = async (
  data: PropertyData,
  mode: ListingMode
): Promise<string> => {
  const modelName = "gemini-2.5-flash";
  const templateToUse = mode === ListingMode.RENTAL ? RENTAL_TEMPLATE : SALE_TEMPLATE;

  const prompt = `
    You are Linus, a Taiwanese Real Estate Agent in Tokyo.
    Task: Fill out the ${mode} template based on the provided JSON data.

    Data: ${JSON.stringify(data)}

    Special Instructions for Sale Template:
    1. **Renovation_Status_Line**: If 'renovationDate' exists, write "▫︎ {renovationDate} 全室室內設備翻新完成". Else, omit.
    2. **Total_Floors_Line**: Use 'totalFloors'.
    3. **Floor_Part**: Mention current floor 'floor'.
    4. **Year_Month**: Use building age/year 'age'.
    5. **Features_List**: List key features (including elevator, security, etc.) using "／" as separator.
    6. **Dynamic Hashtags**: Include area tags like #{Station}生活 #{Area}房產 plus general #日本買房 #東京置產.

    ${TERMINOLOGY_GUIDE}
    Rules: NO Markdown (bold/italics), output plain text only. Professional yet warm tone.

    Template:
    ${templateToUse}
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
    });
    return response.text || "Error generating text.";
  } catch (error) {
    console.error(error);
    return "Generation failed.";
  }
};

export const rewriteListingText = async (
  currentText: string,
  instruction: string
): Promise<string> => {
  const modelName = "gemini-2.5-flash";
  const prompt = `
    You are an expert copywriter. Rewrite this property listing.
    Instruction: ${instruction}
    Text: ${currentText}
    ${TERMINOLOGY_GUIDE}
    Output ONLY the rewritten text. Plain text, no markdown.
  `;
  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
    });
    return response.text || currentText;
  } catch (error) {
    return currentText;
  }
};

export const extractPropertyData = async (
  files: { mimeType: string; data: string }[],
  supplementaryText: string = ""
): Promise<Partial<PropertyData>> => {
  const modelName = "gemini-2.5-flash";

  const prompt = `
    Analyze the documents and supplementary text: "${supplementaryText}"
    Extract the following data into JSON format. Translate to Traditional Chinese.

    Fields to find:
    - address (所在地)
    - line (沿線)
    - station (駅名)
    - walkTime (徒歩時間)
    - price (価格/賃料 - e.g., 8,350萬)
    - layout (間取り - e.g., 1LDK)
    - size (専有面積 - e.g., 45.89)
    - balconySize (バルコニー面積 - e.g., 3.64)
    - floor (所在階 - e.g., 2階)
    - totalFloors (建物階数 - e.g., 地上7階)
    - age (築年月 - e.g., 2010年10月)
    - managementFee (管理費)
    - repairFund (修繕積立金)
    - moveInDate (引渡/入居時期)
    - renovationDate (翻新日期 - Look for "2025年11月フルリフォーム完成" etc)
    - features (設備特色 - Concatenate with "／")

    Rules:
    - If not found, leave as empty string.
    - Be precise with numbers.
    - If multiple stations, pick the closest one for 'station' field.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [
          ...files.map(f => ({ inlineData: f })),
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            address: { type: Type.STRING },
            line: { type: Type.STRING },
            station: { type: Type.STRING },
            walkTime: { type: Type.STRING },
            price: { type: Type.STRING },
            layout: { type: Type.STRING },
            size: { type: Type.STRING },
            balconySize: { type: Type.STRING },
            floor: { type: Type.STRING },
            totalFloors: { type: Type.STRING },
            age: { type: Type.STRING },
            managementFee: { type: Type.STRING },
            repairFund: { type: Type.STRING },
            moveInDate: { type: Type.STRING },
            renovationDate: { type: Type.STRING },
            features: { type: Type.STRING },
          },
        }
      }
    });

    const text = response.text;
    return text ? JSON.parse(text) : {};
  } catch (error) {
    console.error(error);
    return {};
  }
};
